import { useState, useEffect, useCallback } from 'react';
import { useNavigate, Link, NavLink } from 'react-router-dom';
import { YMaps, Map, Placemark } from '@pbe/react-yandex-maps';

import constFlaskURL from '../consts/constFlaskURL'

let loadData = [];


function Home() {
    const [center, setCenter] = useState([55.751574, 37.573856]);
    const [markers, setMarkers] = useState([]);
    const [selectedMarker, setSelectedMarker] = useState(null);
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    useEffect(() => {
        fetchMarkersFromDatabase();
    }, []);

    const handleLogout = async () => {
        setLoading(true);

        try {
            const response = await constFlaskURL.post('/logout');

            if (response.status === 200) 
            {
                setTimeout(() => {
                    navigate('/login');
                }, 1000);
            }
        } catch (err) {
            console.error('Logout error:', err);
        } finally {
            setLoading(false);
        }
    };

    const fetchMarkersFromDatabase = async () => {
        try {
            setLoading(true);

            const locality_crossroad = await constFlaskURL.get('/localities/crossroads');

            for (const item of locality_crossroad.data.items){
                alert(locality_crossroad.data.items[item].crossroads);
            };

            const loadData = {
                items: [
                    {
                        crossroads: {
                            latitude: locality_crossroad.data.items[0].crossroads.latitude,
                            longitude: locality_crossroad.data.items[0].crossroads.longitude,
                            roads_sings: {
                                name_road: locality_crossroad.data.items[0].crossroads.roads_sings.name_road,
                                number_road: locality_crossroad.data.items[0].crossroads.roads_sings.number_road,
                                sings: {
                                    image: locality_crossroad.data.items[0].crossroads.roads_sings.sings.image,
                                    latitude: locality_crossroad.data.items[0].crossroads.roads_sings.sings.latitude,
                                    longitude: locality_crossroad.data.items[0].crossroads.roads_sings.sings.longitude,
                                    name_sing: locality_crossroad.data.items[0].crossroads.roads_sings.sings.name_sing,
                                    sing_id: locality_crossroad.data.items[0].crossroads.roads_sings.sings.sing_id
                                }
                            },
                            type_crossroad: locality_crossroad.data.items[0].crossroads.type_crossroad
                        },
                        id: locality_crossroad.data.items[0].id,
                        latitude: locality_crossroad.data.items[0].latitude,
                        longitude: locality_crossroad.data.items[0].longitude,
                        name_locality: locality_crossroad.data.items[0].name_locality
                    }
                ]
            }
            setMarkers(loadData.items);

            if (loadData.items.length > 0) {
                setCenter([loadData.items[0].crossroads.roads_sings.sings.latitude, loadData.items[0].crossroads.roads_sings.sings.longitude]);
            }

        } catch (error) {
            console.error('Ошибка загрузки маркеров:', error);
        } finally {
            setLoading(false);
        }
    };

    const generateBalloonContent = (marker) => {
        return `
            <div style="
                max-width: 400px; 
                font-family: Arial, sans-serif;
                background: white;
                border-radius: 12px;
                overflow: hidden;
                box-shadow: 0 5px 20px rgba(0,0,0,0.15);
            ">
            <div style="position: relative; height: 200px; overflow: hidden;">
                <img 
                    src"img/${marker.crossroads.roads_sings.sings.image}" 
                    style="
                    width: 100%;
                    height: 100%;
                    object-fit: cover;
                    transition: transform 0.3s;
                    "
                    onmouseover="this.style.transform='scale(1.05)'"
                    onmouseout="this.style.transform='scale(1)'"
                />
            </div>
            <div style="padding: 20px;">
                <h3 style="
                    margin: 0 0 10px 0;
                    color: #333;
                    font-size: 20px;
                    font-weight: 600;
                ">
                    ${marker.crossroads.roads_sings.sings.name_sing}
                </h3>
                <div style="
                    background: #f8f9fa;
                    padding: 15px;
                    border-radius: 8px;
                    margin-bottom: 15px;
                ">
                    <div style="
                    display: grid;
                    grid-template-columns: 1fr 1fr;
                    gap: 10px;
                    margin-bottom: 10px;
                    ">
                        <div>
                            <div style="
                            font-size: 11px;
                            color: #888;
                            margin-bottom: 4px;
                            ">
                            Широта
                        </div>
                        <div style="
                            font-family: 'Courier New', monospace;
                            font-size: 13px;
                            color: #333;
                            font-weight: bold;
                        ">
                        ${marker.crossroads.roads_sings.sings.latitude.toFixed(6)}
                    </div>
                </div>
                <div>
                    <div style="
                        font-size: 11px;
                        color: #888;
                        margin-bottom: 4px;
                    ">
                        Долгота
                    </div>
                    <div style="
                        font-family: 'Courier New', monospace;
                        font-size: 13px;
                        color: #333;
                        font-weight: bold;
                    ">
                        ${marker.crossroads.roads_sings.sings.longitude.toFixed(6)}
                    </div>
                </div>
                </div>
                <div>
                    <div style="
                        font-size: 11px;
                        color: #888;
                        margin-bottom: 4px;
                    ">
                        Адрес
                    </div>
                    <div style="
                        font-size: 13px;
                        color: #333;
                    ">
                        ${marker.name_locality}
                    </div>
                </div>
            </div>
        </div>
        `;
    };

    if (loading) {
        return (
            <div style={{ 
                display: 'flex', 
                justifyContent: 'center', 
                alignItems: 'center', 
                height: '600px',
                flexDirection: 'column',
                gap: '20px'
            }}>
                <div style={{
                width: '50px',
                height: '50px',
                border: '5px solid #f3f3f3',
                borderTop: '5px solid #3498db',
                borderRadius: '50%',
                animation: 'spin 1s linear infinite'
                }}></div>
                <style>{`
                @keyframes spin {
                    0% { transform: rotate(0deg); }
                    100% { transform: rotate(360deg); }
                }
                `}</style>
                <div>Загрузка карты и маркеров...</div>
            </div>
        );
    }

    return (
        <div> 
            {loading ? 
            (
                <div>
                    <p>Загрузка данных...</p>
                </div>
            ) : true ? 
            (
                <div>
                    <nav className='navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0'>
                        <div className='container-fluid py-2'>
                            <Link className='navbar-brand fs-3 fw-bold' to='/main'>Дорожное хозяйство</Link>
                            <div class="btn-group">
                                <button type="button" class="btn btn-info">Пользователь</button>
                                <button type="button" class="btn btn-info dropdown-toggle dropdown-toggle-split" data-bs-toggle="dropdown" aria-expanded="false">
                                    <span class="visually-hidden"></span>
                                </button>
                                <ul class="dropdown-menu">
                                    <li>
                                        <a class="dropdown-item">
                                            <button
                                                onClick={handleLogout} 
                                                className='dropdown-item'
                                                disabled={loading}
                                            >
                                                {loading ? (
                                                    <>
                                                        <span className='spinner'></span>
                                                        Выход...
                                                    </>
                                                ) : 'Выйти'}
                                            </button>
                                        </a>
                                    </li>
                                </ul>
                            </div>
                        </div>
                        <div className='container-fluid bg-dark py-2'>
                            <div className='navbar-nav flex-row'>
                                <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/main' end> Главная </NavLink>
                                <div class="collapse navbar-collapse" id="navbarNavDarkDropdown">
                                    <ul class="navbar-nav">
                                        <li class="nav-item dropdown">
                                            <a class="nav-link dropdown-toggle" href="#" id="navbarDarkDropdownMenuLink" role="button" data-bs-toggle="dropdown" aria-expanded="false">
                                                Дорожные знаки на дорогах
                                            </a>
                                            <ul class="dropdown-menu dropdown-menu-dark" aria-labelledby="navbarDarkDropdownMenuLink">
                                                <li>
                                                    <NavLink style={{ color: 'black' }} className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/roads' end> Дороги </NavLink>
                                                    <NavLink style={{ color: 'black' }} className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/sings' end> Дорожные знаки </NavLink>
                                                    <NavLink style={{ color: 'black' }} className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/roads/sings' end> Знаки на дорогах </NavLink>
                                                </li>
                                            </ul>
                                        </li>
                                        <li class="nav-item dropdown">
                                            <a class="nav-link dropdown-toggle" href="#" id="navbarDarkDropdownMenuLink" role="button" data-bs-toggle="dropdown" aria-expanded="false">
                                                Дорожные знаки на перекрестках
                                            </a>
                                            <ul class="dropdown-menu dropdown-menu-dark" aria-labelledby="navbarDarkDropdownMenuLink">
                                                <li>
                                                    <NavLink style={{ color: 'black' }} className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/type_crossroads' end>Типы перекрестков</NavLink>
                                                    <NavLink style={{ color: 'black' }} className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/crossroads' end>Перекрестки</NavLink>
                                                    <NavLink style={{ color: 'black' }} className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/crossroads/roads/sings' end>Дорожные знаки на перекрестках</NavLink>

                                                </li>
                                            </ul>
                                        </li>
                                        <li class="nav-item dropdown">
                                            <a class="nav-link dropdown-toggle" href="#" id="navbarDarkDropdownMenuLink" role="button" data-bs-toggle="dropdown" aria-expanded="false">
                                                Дорожные знаки на населенных пунктах
                                            </a>
                                            <ul class="dropdown-menu dropdown-menu-dark" aria-labelledby="navbarDarkDropdownMenuLink">
                                                <li>
                                                    <NavLink style={{ color: 'black' }} className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/localities' end>Населенные пункты</NavLink>
                                                    <NavLink style={{ color: 'black' }} className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/localities/crossroads' end>Дорожные знаки на населенных пунктах</NavLink>
                                                </li>
                                            </ul>
                                        </li>
                                    </ul>
                                </div>
                            </div>
                        </div>
                    </nav>
                    <div className='container'>
                        <div style={{ 
                              width: '100%', 
                              maxWidth: '1200px', 
                              margin: '0 auto',
                              padding: '20px'
                            }}>
                                <h1 style={{ marginBottom: '20px', color: '#333' }}>Интерактивная карта.</h1>
                                <div style={{ 
                                    width: '100%', 
                                    height: '600px',
                                    borderRadius: '12px',
                                    overflow: 'hidden',
                                    boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
                                    marginBottom: '20px'
                                }}>
                                <YMaps>
                                    <Map 
                                        state={{ center, zoom: 10 }} 
                                        width="100%" 
                                        height="100%"
                                        modules={['geoObject.addon.balloon', 'geoObject.addon.hint']}
                                    >
                                        {markers.map((marker) => (
                                            <Placemark
                                                key={marker.id}
                                                geometry={[marker.crossroads.roads_sings.sings.latitude, marker.crossroads.roads_sings.sings.longitude]}
                                                options={{
                                                    iconLayout: 'default#image',
                                                    iconImageSize: [48, 48],
                                                    iconImageOffset: [-24, -48],
                                                    hideIconOnBalloonOpen: false,
                                                    openBalloonOnClick: true,
                                                }}
                                                properties={{
                                                    hintContent: `<div style="padding: 5px 10px; font-weight: bold;">${marker.crossroads.roads_sings.sings.name_sing}</div>`,
                                                    balloonContent: generateBalloonContent(marker),
                                                    balloonContentHeader: `<div style="padding: 10px; color: white; font-weight: bold; border-radius: 8px 8px 0 0;">${marker.name_locality}</div>`,
                                                }}
                                                modules={['geoObject.addon.balloon']}
                                                onClick={() => {
                                                    setSelectedMarker(marker);
                                                    console.log('Выбран маркер:', marker.name_locality);
                                                }}
                                            />
                                        ))}
                                    </Map>
                                </YMaps>
                            </div>
                        </div>
                    </div>
                </div>
            ) : (
                <p className='no-data'>Нет данных для отображения</p> 
            )} 
        </div>
    );
}

export default Home;
